SELECT model_name, make, city_mpg
FROM vehicles
WHERE city_mpg > (SELECT AVG(city_mpg) FROM vehicles);

SELECT * FROM vehicles
WHERE price > (SELECT AVG(price) FROM vehicles)
ORDER BY price DESC;

SELECT model_name
FROM vehicles
WHERE horsepower = (SELECT MAX(horsepower) FROM vehicles);

SELECT body_style, AVG(price) AS avg_price
FROM vehicles
GROUP BY body_style;

SELECT DISTINCT v.make
FROM vehicles v
WHERE v.city_mpg > (SELECT AVG(city_mpg) FROM vehicles);
